# Build journal from capture data
python3 << 'PYEOF'
import json, os

capture_file = "session_logs/.tool_capture.jsonl"
entries = []
with open(capture_file) as f:
    for line in f:
        entries.append(json.loads(line))

def make_tool_call(seq, entry):
    """Transform a capture entry into journal schema tool_call."""
    inp = entry.get("input", {})
    resp = entry.get("response", {})

    # Flatten response to a string for the journal output field
    if isinstance(resp, dict):
        # For Bash: use stdout
        if "stdout" in resp:
            output_str = resp.get("stdout", "") or ""
            if resp.get("stderr"):
                output_str += "\nSTDERR: " + resp["stderr"]
        # For Agent: use content
        elif "content" in resp:
            content = resp["content"]
            if isinstance(content, list):
                output_str = "\n".join(
                    item.get("text", "") for item in content 
                    if isinstance(item, dict) and item.get("type") == "text"
                )
            else:
                output_str = str(content)
        # For Read: use contents
        elif "contents" in resp:
            output_str = resp["contents"] or ""
        # For Edit/Write: use filePath + success
        elif "filePath" in resp:
            output_str = f"filePath={resp['filePath']}, success={resp.get('success', '?')}"
        # For Grep/Glob: serialize
        else:
            output_str = json.dumps(resp, ensure_ascii=False)
    else:
        output_str = str(resp)

    # Count lines/chars for the result
    lines_count = output_str.count("\n") + 1 if output_str else 0
    chars_count = len(output_str)

    return {
        "sequence": seq,
        "tool": entry["tool"],
        "parameters": inp,
        "result": {
            "output": output_str,
            "truncated": entry.get("input_truncated", False) or entry.get("response_truncated", False),
            "original_length_lines": lines_count,
            "original_length_chars": chars_count,
        }
    }

# Build tool_calls from entries (all are from turn 1 of this session)
tool_calls = []
for i, entry in enumerate(entries, 1):
    tool_calls.append(make_tool_call(i, entry))

