        { type: 'load_sf2', sf2Bytes: sf2Bytes },
      );

      // Wait for confirmation
      return new Promise((resolve) => {
        const timeout = setTimeout(() => {
          console.warn('WasmSynth: SF2 load timed out');
          resolve(false);
        }, 30000); // 30s timeout for large SF2 files

