          this.audio.currentTime = 0;
        } else {
          await this.loadMp3Track(this.currentTrack - 1);
          if (this.isPlaying) this.play();
        }
        break;
    }

    this._updateMediaSession();
  }

  /** Go to next track/MIDI. */
  async nextTrack() {
