      if (mutEl) mutEl.textContent = '';
      if (sourceEl) sourceEl.textContent = '';
      if (notesEl) notesEl.textContent = '';

      this.midiInfoPanel.classList.add('visible');
    } else {
      this.midiInfoPanel.classList.remove('visible');
    }
