        result.push({
          t: ev[0], dur: ev[1], note: ev[2],
          inst: instMap[String(ev[3])] || 'unknown',
          vel: ev[4], ch: ev[5],
        });
      }
      if (ev[0] > endTime) break;
    }
    return result;
  }

