}

/* ---------- ID3 Info (near play controls) ---------- */
.music-id3 {
  display: flex; flex-direction: column; justify-content: center;
  gap: 1px; min-width: 0; max-width: 180px; flex-shrink: 1;
  overflow: hidden;
}

.id3-title {
  font-size: 11px; font-weight: 700; color: var(--text);
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}

.id3-artist {
  font-size: 9px; color: var(--accent);
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}

.id3-album-info {
  font-size: 8px; color: var(--text-dim);
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}

/* ---------- Interstitial Overlay ---------- */
.interstitial-overlay {
  position: fixed; inset: 0;
  background: radial-gradient(ellipse at 50% 50%, #0a0a40 0%, #050510 80%);
  display: flex; align-items: center; justify-content: center;
  z-index: 200;
  animation: interstitial-fade-in 0.5s ease;
}

.interstitial-content { text-align: center; }

.interstitial-logo {
  font-size: 80px; line-height: 1;
  filter: drop-shadow(0 0 30px rgba(100, 150, 255, 0.5));
  animation: interstitial-pulse 2s ease-in-out infinite;
}

.interstitial-text {
  font-size: 24px; font-weight: 700;
  letter-spacing: 0.15em; text-transform: uppercase;
  background: linear-gradient(135deg, #4af, #a4f);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-top: 16px;
}

@keyframes interstitial-fade-in { from { opacity: 0; } to { opacity: 1; } }
@keyframes interstitial-pulse { 0%, 100% { transform: scale(1); } 50% { transform: scale(1.1); } }

/* ---------- Note Info Panel ---------- */
.note-info {
  position: absolute; bottom: 48px; left: 0; right: 0;
  padding: 3px 12px;
  background: rgba(5, 5, 16, 0.7); backdrop-filter: blur(4px);
  z-index: 9; max-height: 50px; overflow: hidden;
  font-size: 9px; color: var(--text-dim); letter-spacing: 0.05em;
  display: none;
}

.note-info.visible { display: block; }
.note-info-content { display: flex; flex-wrap: wrap; gap: 3px 8px; }

.note-tag {
  display: inline-flex; align-items: center; gap: 2px;
  padding: 1px 4px; border-radius: 3px;
  background: rgba(255, 255, 255, 0.05); white-space: nowrap;
}

.note-tag .note-pitch { color: var(--accent); font-weight: 600; }
.note-tag .note-inst { color: #888; }

/* ---------- Track Overlay ---------- */
.track-overlay {
  position: fixed; inset: 0;
  background: rgba(0, 0, 0, 0.7);
  display: none; align-items: center; justify-content: center;
  z-index: 100;
}
.track-overlay.visible { display: flex; }

.track-list-panel {
  position: relative;
  background: rgba(15, 15, 30, 0.95);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 12px; padding: 16px;
  max-width: 420px; width: 90%;
  max-height: 70vh; overflow-y: auto;
}

.track-list-panel .track-entry {
  padding: 8px 10px; cursor: pointer; border-radius: 5px;
  font-size: 12px; color: var(--text-dim); transition: all 0.2s;
}
.track-list-panel .track-entry:hover { background: rgba(255, 255, 255, 0.06); color: var(--text); }
.track-list-panel .track-entry.active { color: var(--accent); background: rgba(100, 180, 255, 0.08); }

/* ---------- MIDI Info Panel ---------- */
.midi-info {
  position: absolute; top: 40px; right: 10px;
  padding: 6px 10px; border-radius: 8px;
  background: rgba(5, 5, 16, 0.8); backdrop-filter: blur(4px);
  font-size: 10px; z-index: 10;
  max-width: 280px; display: none;
  border: 1px solid rgba(255, 255, 255, 0.08);
}

.midi-info.visible { display: block; }

.midi-info-source {
  color: rgba(180, 220, 255, 0.8); font-size: 9px;
  font-style: italic; margin-bottom: 2px;
}

.midi-info-notes {
  color: rgba(180, 220, 255, 0.6); font-size: 9px;
  margin-bottom: 3px;
}

.midi-info-composer {
  color: var(--accent); font-weight: 700;
  font-size: 12px; margin-bottom: 2px;
}

.midi-info-piece {
  color: var(--text); font-style: italic;
  margin-bottom: 2px; line-height: 1.3;
}

.midi-info-era {
  color: var(--text-dim); font-size: 9px;
  text-transform: uppercase; letter-spacing: 0.08em;
}

.midi-info-mutation {
  color: #a4a; font-size: 9px; margin-top: 3px;
}

/* ---------- Pause Overlay ---------- */
.pause-overlay {
  position: fixed; inset: 0;
  background: rgba(5, 5, 16, 0.8);
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  z-index: 50;
}
.pause-overlay h2 { font-size: 32px; letter-spacing: 0.2em; margin-bottom: 12px; }
.pause-overlay p { font-size: 13px; color: var(--text-dim); }

/* ---------- Mode-specific ---------- */
body.mode-player #main-canvas { opacity: 0.15; }
body.mode-player .hud-score, body.mode-player .hud-label#hud-score-label,
body.mode-player .hud-names, body.mode-player .hud-spacetime { display: none !important; }

body.mode-grid #main-canvas { opacity: 1; }
body.mode-grid .hud-score, body.mode-grid .hud-label#hud-score-label,
body.mode-grid .hud-names, body.mode-grid .hud-spacetime { display: none !important; }

/* ---------- Touch / Mobile ---------- */
button, .mode-btn, .player-count-btn, .tab-btn, .dim-btn,
.overlay-close, .mutation-option, .theme-chip, .star-chip {
  touch-action: manipulation;
}

/* Safe-area insets for notched devices (iPhone X+, etc.) */
@supports (padding: max(0px)) {
  .hud {
    padding-top: max(6px, env(safe-area-inset-top));
    padding-right: max(12px, env(safe-area-inset-right));
  }
  .music-bar {
    padding-bottom: max(5px, env(safe-area-inset-bottom));
    padding-left: max(12px, env(safe-area-inset-left));
    padding-right: max(12px, env(safe-area-inset-right));
  }
}

/* ---------- Responsive ---------- */

/* Tablets (768px) */
@media (max-width: 768px) {
  .overlay-panel { max-width: 90vw; }
  .hud-btn { min-width: 44px; min-height: 44px; }
}

/* Phones (640px) */
@media (max-width: 640px) {
  .hud { padding: 3px 6px; }
  .hud-score { font-size: 16px; }
  .hud-track { max-width: 90px; font-size: 10px; }
  .hud-epoch { font-size: 10px; }
  .hud-spacetime { display: none; }
  .music-bar { padding: 3px 6px; gap: 4px; height: 44px; }
  .music-vol, .music-volume { display: none; }
  .music-time { font-size: 10px; min-width: 55px; }
  .music-id3 { max-width: 100px; }
  .id3-album-info { display: none; }
  .mode-select, .player-count-select { gap: 6px; }
  .mode-btn, .player-count-btn { padding: 10px 14px; min-width: 70px; min-height: 44px; }
  .mode-icon { font-size: 20px; }
  .star-grid { max-height: 150px; overflow-y: auto; }
  .overlay-panel { padding: 14px; }
  .help-table td { font-size: 10px; padding: 2px 4px; }
  .mutation-grid { grid-template-columns: repeat(2, 1fr); }
  .style-row label { flex: 0 0 80px; }
  .music-seek::-webkit-slider-thumb { width: 20px; height: 20px; }
  .music-seek::-moz-range-thumb { width: 20px; height: 20px; }
}

/* Small phones (400px) */
@media (max-width: 400px) {
  #prev-btn, #next-btn { font-size: 14px; padding: 4px; }
  .mode-tabs { gap: 2px; }
  .hud-center { display: none; }
  .mutation-grid { grid-template-columns: repeat(2, 1fr); }
  .music-id3 { display: none; }
}

/* Landscape phones — reduce vertical space usage */
@media (orientation: landscape) and (max-height: 500px) {
  .hud { padding: 2px 6px; }
  .music-bar { height: 40px; }
  .title-content { padding: 8px; }
  .overlay-panel { max-height: 95vh; overflow-y: auto; }
}

/* Credits panel */
.credits-panel { max-height: 80vh; overflow-y: auto; }
.credits-content h3 { color: var(--accent); margin-top: 1.2em; margin-bottom: 0.3em; font-size: 0.95em; }
.credits-content p { font-size: 0.85em; line-height: 1.4; margin: 0.2em 0; }
.credits-content a { text-decoration: none; }
.credits-content a:hover { text-decoration: underline; }


/* Instrument selection */
.instrument-panel { max-height: 80vh; overflow-y: auto; }
.instrument-hint { font-size: 0.8em; opacity: 0.6; margin-bottom: 1em; }
.instrument-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 8px; }
.instrument-chip {
  padding: 10px; border-radius: 8px; border: 1px solid rgba(100,160,255,0.2);
  background: rgba(20,30,50,0.8); color: rgba(200,220,240,0.5); cursor: pointer;
  font-size: 0.85em; transition: all 0.2s;
}
.instrument-chip.enabled {
  border-color: var(--accent); color: #fff; background: rgba(40,60,100,0.6);
}
.instrument-chip:hover { border-color: var(--accent); }


/* MIDI source and effects tags in note info */
.midi-source-tag { background: rgba(100,160,255,0.15); border: 1px solid rgba(100,160,255,0.3); }
.effects-tag { background: rgba(255,160,80,0.15); border: 1px solid rgba(255,160,80,0.3); font-style: italic; }

